{
var size = context.TileSize;
var seed = GetInt(parameters, "seed", context.Seed);
var roadWidth = GetFloat(parameters, "roadWidth", 0.5f);
var shoulderWidth = GetFloat(parameters, "shoulderWidth", 0.3f);
var edgeRoughness = GetFloat(parameters, "edgeRoughness", 0.3f);
var rutDepth = GetFloat(parameters, "rutDepth", 0.2f);
var gravelDensity = GetFloat(parameters, "gravelDensity", 0.3f);
var roadLayout = GetChoice(parameters, "roadLayout", "StraightVertical");
var cornerRoundness = GetFloat(parameters, "cornerRoundness", 0.5f);
var centerLine = GetFloat(parameters, "centerLine", 0.3f);
var centerLineRoughness = GetFloat(parameters, "centerLineRoughness", 0.3f);

// Road palette (0..1 floats)
var asphaltDark   = (R: 0.176f, G: 0.176f, B: 0.196f);
var asphaltBase   = (R: 0.255f, G: 0.255f, B: 0.275f);
var asphaltLight  = (R: 0.333f, G: 0.333f, B: 0.353f);
var asphaltLine   = (R: 0.863f, G: 0.784f, B: 0.275f);
var asphaltLineWhite = (R: 0.824f, G: 0.824f, B: 0.843f);
var shoulderDark  = (R: 0.412f, G: 0.333f, B: 0.216f);
var shoulderLight = (R: 0.549f, G: 0.451f, B: 0.314f);

var roadHW = 0.05f + roadWidth * 0.25f;
var shoulderW = 0.02f + shoulderWidth * 0.08f;

int pxSize = Math.Max(1, size / 32);

var result = new PixelBuffer(size, size);
result.ParallelForEachPixel((x, y) =>
{
    var wx = Mod(x, size);
    var wy = Mod(y, size);
    var normX = wx / (float)size;
    var normY = wy / (float)size;

    var pxX = MathF.Floor(wx / (float)pxSize) * pxSize;
    var pxY = MathF.Floor(wy / (float)pxSize) * pxSize;

    var roadSample = SampleRoad(normX, normY, roadLayout, roadHW, cornerRoundness);
    var distToCenter = roadSample.Distance;
    var pathPos = roadSample.PathPos;
    var hasPathPos = roadSample.HasPath;

    var whiteLineDist = distToCenter + GetRoadDistortion(pxX, pxY, size, seed + 50, edgeRoughness);
    var centerLineDist = distToCenter + GetRoadDistortion(pxX, pxY, size, seed + 60, centerLineRoughness);
    var shoulderDist = distToCenter + GetRoadDistortion(pxX, pxY, size, seed + 70, edgeRoughness);

    float r, g, b;

    if (distToCenter < roadHW)
    {
        if (whiteLineDist > roadHW - 0.02f)
        {
            r = asphaltLineWhite.R; g = asphaltLineWhite.G; b = asphaltLineWhite.B;
        }
        else
        {
            var gritNoise = TileableFractalNoise(wx * 2f, wy * 2f, size, 1, 1f, 1f, seed + 10);
            float asR = asphaltBase.R, asG = asphaltBase.G, asB = asphaltBase.B;

            if (gritNoise > 1f - gravelDensity * 0.2f)
            {
                asR = asphaltLight.R; asG = asphaltLight.G; asB = asphaltLight.B;
            }
            else if (gritNoise < gravelDensity * 0.2f)
            {
                asR = asphaltDark.R; asG = asphaltDark.G; asB = asphaltDark.B;
            }

            var rutN = GetRutNoise(distToCenter, roadHW, wx, wy, size, seed, rutDepth);
            if (rutN > 0f)
            {
                var clampRut = Math.Clamp(rutN, 0f, 0.85f);
                asR = Lerp(asR, asphaltDark.R, clampRut);
                asG = Lerp(asG, asphaltDark.G, clampRut);
                asB = Lerp(asB, asphaltDark.B, clampRut);
            }

            var clWidth = Math.Max(0.003f, centerLine * roadHW * 0.45f);
            if (centerLine > 0f && hasPathPos)
            {
                if (centerLineDist < clWidth)
                {
                    float dashPhase = (pathPos * 8f) % 1f;
                    if (dashPhase < 0.5f)
                    {
                        asR = asphaltLine.R; asG = asphaltLine.G; asB = asphaltLine.B;
                    }
                }
            }

            r = asR; g = asG; b = asB;
        }
    }
    else if (shoulderDist < roadHW + shoulderW)
    {
        var shoulderTex = TileableFractalNoise(wx * 1.25f, wy * 1.25f, size, 1, 1f, 1f, seed + 20);
        var sdR = shoulderTex > 0.5f ? shoulderLight.R : shoulderDark.R;
        var sdG = shoulderTex > 0.5f ? shoulderLight.G : shoulderDark.G;
        var sdB = shoulderTex > 0.5f ? shoulderLight.B : shoulderDark.B;

        if (edgeRoughness <= 0f)
        {
            r = sdR; g = sdG; b = sdB;
        }
        else
        {
            var shoulderPos = (shoulderDist - roadHW) / shoulderW;
            var shoulderEdgeNoise = TileableFractalNoise(wx * 0.875f, wy * 0.875f, size, 1, 1f, 1f, seed + 21);
            if (shoulderPos > shoulderEdgeNoise * 0.8f + 0.2f)
            {
                r = 0f; g = 0f; b = 0f;
            }
            else
            {
                r = sdR; g = sdG; b = sdB;
            }
        }
    }
    else
    {
        r = 0f; g = 0f; b = 0f;
    }

    result.SetPixel(x, y, Math.Clamp(r, 0f, 1f), Math.Clamp(g, 0f, 1f), Math.Clamp(b, 0f, 1f), 1f);
});

return result;


// ---- Helper functions ----

static float GetRoadDistortion(float pxX, float pxY, int sz, int s, float rough)
{
    if (rough <= 0f) return 0f;
    return (TileableFractalNoise(pxX * 0.5f, pxY * 0.5f, sz, 1, 1f, 1f, s) - 0.5f) * rough * 0.06f;
}

static float GetRutNoise(float dist, float halfW, float wxx, float wyy, int sz, int s, float rDepth)
{
    if (rDepth <= 0f || halfW <= 0f) return 0f;
    var normDist = dist / halfW;
    var rutBand = MathF.Abs(normDist - 0.42f);
    if (rutBand >= 0.14f) return 0f;
    var rutMask = (0.14f - rutBand) / 0.14f;
    var rutVar = 0.75f + TileableFractalNoise(wxx * 1.5f, wyy * 1.5f, sz, 1, 1f, 1f, s + 30) * 0.25f;
    return rutMask * rutVar * rDepth;
}

static (float Distance, float PathPos, bool HasPath) SampleRoad(float nX, float nY, string layout, float hw, float roundness)
{
    if (TryTransformToCanonical(layout, nX, nY, out var cx, out var cy))
        return SampleCanonicalCorner(cx, cy, hw, roundness);

    switch (layout)
    {
        case "StraightVertical": return (MathF.Abs(nX - 0.5f), nY, true);
        case "StraightHorizontal": return (MathF.Abs(nY - 0.5f), nX, true);
        default: return (GetRoadDistance(nX, nY, layout, hw, roundness), 0f, false);
    }
}

static bool TryTransformToCanonical(string layout, float nX, float nY, out float cx, out float cy)
{
    switch (layout)
    {
        case "CornerNE": cx = nX; cy = nY; return true;
        case "CornerSE": cx = nX; cy = 1f - nY; return true;
        case "CornerSW": cx = 1f - nX; cy = 1f - nY; return true;
        case "CornerNW": cx = 1f - nX; cy = nY; return true;
        default: cx = 0f; cy = 0f; return false;
    }
}

static (float Distance, float PathPos, bool HasPath) SampleCanonicalCorner(float nX, float nY, float hw, float roundness)
{
    var cr = Math.Clamp(roundness, 0f, 1f);
    var curveR = Math.Max(0f, 0.5f - hw) * cr;
    var vertEnd = 0.5f - curveR;
    var horizStart = 0.5f + curveR;
    var arcLen = MathF.PI * 0.5f * curveR;
    var totalLen = Math.Max(0.0001f, vertEnd + arcLen + (1f - horizStart));

    var bestDist = 1e10f;
    var bestPath = 0f;

    var seg1 = SampleSegment(nX, nY, 0.5f, 0f, 0.5f, vertEnd, 0f);
    if (seg1.Distance < bestDist) { bestDist = seg1.Distance; bestPath = seg1.PathPos; }

    var seg2 = SampleSegment(nX, nY, horizStart, 0.5f, 1f, 0.5f, vertEnd + arcLen);
    if (seg2.Distance < bestDist) { bestDist = seg2.Distance; bestPath = seg2.PathPos; }

    if (curveR > 0f)
    {
        var ctrX = 0.5f + curveR;
        var ctrY = 0.5f - curveR;
        var dx = nX - ctrX;
        var dy = nY - ctrY;
        var angle = MathF.Atan2(dy, dx);
        if (angle >= MathF.PI * 0.5f && angle <= MathF.PI)
        {
            var radialDist = MathF.Abs(MathF.Sqrt(dx * dx + dy * dy) - curveR);
            var arcProg = (MathF.PI - angle) / (MathF.PI * 0.5f);
            var arcPath = vertEnd + arcProg * arcLen;
            if (radialDist < bestDist) { bestDist = radialDist; bestPath = arcPath; }
        }
    }

    return (bestDist, bestPath / totalLen, true);
}

static (float Distance, float PathPos, bool HasPath) SampleSegment(float px, float py, float ax, float ay, float bx, float by, float lenOff)
{
    var dx = bx - ax;
    var dy = by - ay;
    var lenSq = dx * dx + dy * dy;
    if (lenSq <= 0f)
    {
        var ptDist = MathF.Sqrt((px - ax) * (px - ax) + (py - ay) * (py - ay));
        return (ptDist, lenOff, true);
    }
    var t = Math.Clamp(((px - ax) * dx + (py - ay) * dy) / lenSq, 0f, 1f);
    var cx = ax + dx * t;
    var cy = ay + dy * t;
    var dist = MathF.Sqrt((px - cx) * (px - cx) + (py - cy) * (py - cy));
    var segLen = MathF.Sqrt(lenSq);
    return (dist, lenOff + segLen * t, true);
}

static float GetRoadDistance(float nX, float nY, string layout, float roadW, float cRoundness)
{
    var center = 0.5f;
    var dist = 1e10f;

    GetConnections(layout, out var up, out var right, out var down, out var left);

    if (up && nY <= center) dist = MathF.Min(dist, MathF.Abs(nX - center));
    if (down && nY >= center) dist = MathF.Min(dist, MathF.Abs(nX - center));
    if (left && nX <= center) dist = MathF.Min(dist, MathF.Abs(nY - center));
    if (right && nX >= center) dist = MathF.Min(dist, MathF.Abs(nY - center));

    if (IsIntersection(layout))
    {
        var cx = MathF.Abs(nX - center);
        var cy = MathF.Abs(nY - center);
        if (cx < roadW && cy < roadW)
        {
            if (cRoundness > 0f)
            {
                var maxR = roadW;
                var rSq = cx * cx + cy * cy;
                var mix = MathF.Max(cx, cy);
                var rounded = MathF.Sqrt(rSq);
                dist = MathF.Min(dist, Lerp(mix, rounded, cRoundness) * 0.5f);
            }
            else
            {
                dist = MathF.Min(dist, MathF.Max(cx, cy) * 0.5f);
            }
        }
    }

    return dist >= 1e9f ? 1f : dist;
}

static void GetConnections(string layout, out bool up, out bool right, out bool down, out bool left)
{
    up = false; right = false; down = false; left = false;
    switch (layout)
    {
        case "StraightVertical": up = true; down = true; break;
        case "StraightHorizontal": left = true; right = true; break;
        case "CornerNE": up = true; right = true; break;
        case "CornerSE": right = true; down = true; break;
        case "CornerSW": down = true; left = true; break;
        case "CornerNW": left = true; up = true; break;
        case "TJunctionUp": left = true; right = true; down = true; break;
        case "TJunctionRight": up = true; down = true; left = true; break;
        case "TJunctionDown": left = true; right = true; up = true; break;
        case "TJunctionLeft": up = true; down = true; right = true; break;
        case "Cross": up = true; right = true; down = true; left = true; break;
    }
}

static bool IsIntersection(string layout)
{
    return layout != "StraightVertical" && layout != "StraightHorizontal";
}
}
